import web3

class AuthenticationService:
    def __init__(self):
        self.web3 = web3.Web3(web3.HTTPProvider('https://mainnet.infura.io'))

    def verify_signature(self, signed_message):
        message = signed_message['data']
        signature = signed_message['signature']
        address = self.recover_address(signed_message)

        if not self.web3.eth.account.recoverHash(message, signature):
            return False
        else:
            return address